import { Component, Host, h, Prop, EventEmitter, Event, State, Watch } from '@stencil/core';
import { isEmptyArray, isNullOrUndefined } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-paginator',
  styleUrl: 'mx-paginator.css',
  shadow: false
})
export class MxPaginator {
  /** Sets items array. */
  @Prop({ mutable: true }) items: Array<any> = [];
  /** Sets whether the input box is compact or not. */
  @Prop() readonly isCompact: boolean = false;
  /** Sets total item */
  @Prop({ mutable: true }) totalItems: number = 0;
  /** Sets items per page */
  @Prop({ mutable: true }) itemsPerPage: number = 10;
  /**Set total items to display */
  @Prop() readonly displayTotalItems: boolean = false;
  /**Set total items to display per page  */
  @Prop() readonly displayItemsPerPage: boolean = false;
  /**Set items per page dropdown */
  @Prop() readonly itemsPerPageDropdown: boolean = false;
  /** Set item per page list */
  @Prop({ mutable: true }) itemsPerPageList: Array<any> = [];
  /**Set current page number */
  @Prop({ mutable: true }) currentPage: number;

  @State() showTotalItems: boolean;
  @State() totalPages: number = 0;
  @State() itemsPerPageObj: ItemPage;
  @State() currentPageObj: ItemPage;
  @State() totalItemsStr: any;
  @State() startItem: number = 0;
  @State() endItem: number = 0;
  @State() _currentPageValue: number;

  /** Emits event whenever page is changed. */
  @Event() pageChanged: EventEmitter;
  /** Emits event whenever item per page is changed. */
  @Event() itemsPerPageChanged: EventEmitter;

  set _currentPage(currentVal: number) {
    if (this.isInvalidCurrentPage()) {
      this.currentPage = 1;
    }
    this._currentPageValue = currentVal;
  }

  get _currentPage() {
    return this._currentPageValue;
  }

  @Watch('currentPage')
  handleItemChange(newValue: number) {
    this._currentPage = newValue;
  }

  @Watch('totalItems')
  handleTotalItems(value: number) {
    this.totalItems = value;
    const index = this.getItemsPerPageIndex();
    this.setItemsPerPageObj(index);
  }

  componentWillLoad() {
    this.defaultItemsPerPageList();
    if (isNullOrUndefined(this.totalItems)) {
      this.totalItems = 0;
    }
    if (isNullOrUndefined(this.itemsPerPage)) {
      this.itemsPerPage = 10;
      this.setItemsPerPageObj(this.getItemsPerPageIndex());
    }
    const index = this.getItemsPerPageIndex();
    this.setItemsPerPageObj(index);
    if (this.isInvalidCurrentPage()) {
      this.currentPage = 1;
    }
    this.computeTotalPages();
  }

  componentWillRender() {
    this.showTotalItems = this._showTotalItems();
    this.computeTotalPages();
  }

  private setItemsPerPageObj(index) {
    if ((index === -1 || isNullOrUndefined(this.itemsPerPage)) && !isEmptyArray(this.itemsPerPageList)) {
      this.itemsPerPage = this.itemsPerPageList[0].value;
    }
    this.itemsPerPageObj = { label: this.itemsPerPage.toString(), value: this.itemsPerPage };
  }

  private getItemsPerPageIndex() {
    return this.getIndexOfValueInItemsPerPage(this.itemsPerPage);
  }

  private getIndexOfValueInItemsPerPage(value) {
    return this.itemsPerPageList.findIndex((item) => item.value === value);
  }

  private toIntegerVal(value: number) {
    return parseInt(value.toString(), 10);
  }

  private setCurrentPageObj() {
    this.currentPageObj = { label: this.currentPage.toString(), value: this.currentPage };
  }

  private defaultItemsPerPageList() {
    if (isNullOrUndefined(this.itemsPerPageList) || isEmptyArray(this.itemsPerPageList)) {
      this.itemsPerPageList = [
        {
          label: '10',
          value: 10
        },
        {
          label: '25',
          value: 25
        },
        {
          label: '50',
          value: 50
        },
        {
          label: 'All',
          value: this.totalItems
        }
      ];

      this.itemsPerPageObj = {
        label: '10',
        value: 10
      };
    }

    // set value by references
    if (this.getIndexOfValueInItemsPerPage(this.totalItems) === -1) {
      const lastItem = this.itemsPerPageList[this.itemsPerPageList.length - 1];
      if (lastItem.label === 'All') {
        lastItem.value = this.totalItems;
      }
    }
  }

  private readonly updateCurrentPage = (pageNum: any) => {
    this.currentPage = pageNum;
    this.totalPages = Math.ceil(this.toIntegerVal(this.totalItems) / this.toIntegerVal(this.itemsPerPage));
    this.setCurrentPageObj();
    this.pageChanged.emit({
      currentPage: this.currentPage,
      totalPages: this.totalPages,
      itemsPerPage: this.itemsPerPage
    });
  };

  private readonly prevPage = () => {
    this.updateCurrentPage(this.currentPage - 1);
  };

  private isPrevPageDisabled() {
    return this.currentPage === 1;
  }

  private readonly onCurrentPageChange = (event: CustomEvent) => {
    this.updateCurrentPage(event.detail.value);
  };

  private readonly nextPage = () => {
    this.updateCurrentPage(this.currentPage + 1);
  };

  private isNextPageDisabled() {
    return this.currentPage === this.totalPages;
  }

  private computeTotalPages() {
    this.totalPages = Math.ceil(this.toIntegerVal(this.totalItems) / this.toIntegerVal(this.itemsPerPage));
    this.currentPage = this.toIntegerVal(this.currentPage);
    this.currentPage = this.currentPage > this.totalPages ? this.totalPages : this.currentPage;
    this.setCurrentPageObj();
    this.computeTotalItemList();
  }

  private computeTotalItemList() {
    this.items = [];
    for (let i = 1; i <= this.totalPages; i++) {
      this.items.push({
        label: i.toString(),
        value: i
      });
    }
  }

  private readonly _showTotalItems = () => {
    if (this.displayTotalItems) {
      this.totalItemsStr = `${this.totalItems} Items`;
    }
    if (this.displayItemsPerPage) {
      this.startItem = this.itemsPerPage * (this.currentPage - 1) + 1;
      this.endItem =
        this.itemsPerPage * this.currentPage > this.totalItems ? this.totalItems : this.itemsPerPage * this.currentPage;
      this.totalItemsStr = `Displaying ${this.startItem}-${this.endItem} of ${this.totalItems} Items`;
    }
    return this.displayTotalItems || this.displayItemsPerPage;
  };

  private isInvalidCurrentPage() {
    return this.currentPage <= 0 || isNullOrUndefined(this.currentPage) || isNaN(this.currentPage);
  }

  private readonly updateItemsPerPage = (event: CustomEvent) => {
    const itemsPerPage = event.detail.label;
    this.itemsPerPage =
      itemsPerPage.toString().toLowerCase() === 'all' ? this.totalItems : this.toIntegerVal(itemsPerPage);
    this.itemsPerPageChanged.emit({ itemsPerPage: this.itemsPerPage });
    this.updateCurrentPage(1);
    this.computeTotalPages();
  };

  render() {
    return (
      <Host>
        {this.totalItems > 0 ? (
          <div class='mx-paginator-wrapper'>
            {this.itemsPerPageDropdown ? (
              <div class='items-per-page-container' aria-label="'Select Items Per Page'">
                <mx-single-select
                  class='items-per-page-dropdown'
                  input-id='items-per-page-dropdown'
                  is-compact={this.isCompact}
                  itemSelected={this.itemsPerPageObj}
                  onItemChange={this.updateItemsPerPage}
                  items={this.itemsPerPageList}
                  width='100px'></mx-single-select>
                <kds-label class='text-primary m-8'>Items Per Page</kds-label>
              </div>
            ) : (
              ''
            )}
            <div class='navigation-container' aria-label="'Select Current Page'">
              {this.showTotalItems ? <kds-label class='text-primary m-8'>{this.totalItemsStr}</kds-label> : ''}
              <kds-button
                class='left-chevron'
                type='button'
                variant='border'
                aria-label="'Previous Page'"
                onClick={this.prevPage}
                compact={this.isCompact}
                disabled={this.isPrevPageDisabled()}>
                <kds-icon-caret-left />
              </kds-button>
              <kds-label class='text-primary m-8'>Page</kds-label>
              <mx-single-select
                class='current-page-dropdown'
                input-id='current-page-dropdown'
                is-compact={this.isCompact}
                onItemChange={this.onCurrentPageChange}
                itemSelected={this.currentPageObj}
                items={this.items}
                width='100px'></mx-single-select>
              <kds-label class='text-primary m-8'>of {this.totalPages}</kds-label>
              <kds-button
                class='right-chevron'
                type='button'
                variant='border'
                aria-label="'Next Page'"
                onClick={this.nextPage}
                compact={this.isCompact}
                disabled={this.isNextPageDisabled()}>
                <kds-icon-caret-right />
              </kds-button>
            </div>
          </div>
        ) : (
          ''
        )}
      </Host>
    );
  }
}
